import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
// Import all your page components
import AuthorityPage from './pages/Authority';
import BinPage from './pages/Bin';
import DriverPage from './pages/Driver';
import UserPage from './pages/User';
import VehiclePage from './pages/Vehicle';

function App() {
  const appStyles = {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  };

  const containerStyles = {
    maxWidth: '1400px',
    margin: '0 auto',
    padding: '20px',
    minHeight: 'calc(100vh - 80px)',
  };

  const welcomeStyles = {
    textAlign: 'center',
    color: 'white',
    fontSize: '2.5rem',
    fontWeight: '300',
    marginTop: '60px',
    textShadow: '0 2px 4px rgba(0,0,0,0.3)',
    background: 'rgba(255,255,255,0.1)',
    padding: '40px',
    borderRadius: '15px',
    backdropFilter: 'blur(10px)',
    border: '1px solid rgba(255,255,255,0.2)',
  };

  return (
    <div style={appStyles}>
      <Router>
        <Navbar />
        <div style={containerStyles}>
          <Routes>
            {/* Default landing page */}
            <Route path="/" element={
              <div style={welcomeStyles}>
                <h1>🗑️ Waste Management System</h1>
                <p style={{ fontSize: '1.2rem', marginTop: '20px', opacity: 0.9 }}>
                  Efficient Database Management for Waste Collection Operations
                </p>
                <div style={{ 
                  display: 'grid', 
                  gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', 
                  gap: '20px', 
                  marginTop: '40px' 
                }}>
                  <div style={{ background: 'rgba(255,255,255,0.1)', padding: '20px', borderRadius: '10px' }}>
                    <h3>👥 Authority Management</h3>
                    <p>Manage waste management authorities and their hierarchies</p>
                  </div>
                  <div style={{ background: 'rgba(255,255,255,0.1)', padding: '20px', borderRadius: '10px' }}>
                    <h3>🚛 Vehicle Management</h3>
                    <p>Track and manage waste collection vehicles</p>
                  </div>
                  <div style={{ background: 'rgba(255,255,255,0.1)', padding: '20px', borderRadius: '10px' }}>
                    <h3>🗂️ Bin Management</h3>
                    <p>Monitor waste bins and their locations</p>
                  </div>
                  <div style={{ background: 'rgba(255,255,255,0.1)', padding: '20px', borderRadius: '10px' }}>
                    <h3>👤 User Management</h3>
                    <p>Manage system users and their assignments</p>
                  </div>
                  <div style={{ background: 'rgba(255,255,255,0.1)', padding: '20px', borderRadius: '10px' }}>
                    <h3>🚗 Driver Management</h3>
                    <p>Handle driver information and assignments</p>
                  </div>
                </div>
              </div>
            } />

            {/* Routes for each entity management page */}
            <Route path="/authority" element={<AuthorityPage />} />
            <Route path="/bin" element={<BinPage />} />
            <Route path="/driver" element={<DriverPage />} />
            <Route path="/user" element={<UserPage />} />
            <Route path="/vehicle" element={<VehiclePage />} />
          </Routes>
        </div>
      </Router>
    </div>
  );
}

export default App;
